```java
public class LogParser {
    public static String parseLog(String log) {
        String[] parts = log.split(" ");
        String[] template = new String[parts.length];
        for (int i = 0; i < parts.length; i++) {
            template[i] = parts[i];
            if (i!= parts.length - 1) {
                template[i] += " <>";
            }
        }
        return String.join(" ", template);
    }
}
```

